INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (131, 135555, 6, 269, '由金鱼想到的……', '生日的时候，妹送给我两只金鱼，一只黑的、一只红的。金鱼很小，自然占不了多大的地方，只需要一个不大的玻璃瓶。每天，往瓶子里扔几粒饲料，举手之劳，不足挂齿。但对于金鱼来说，这是一天最快乐的时候。十天后的一个下午，突然有了观赏金鱼的雅致。于是把装鱼的瓶子移动至房间一个光线充足的角落。新的环境，新的气象，金鱼似乎也感觉到了――两只鱼快乐的游着。呼吸着新的空气，享受着新的改变。或许是因为金鱼太高兴了，只看见一道黑色从我眼前滑过，瞬间又落回瓶子里。很漂亮，虽然不及彩虹。还没等我反应过来，另一道黑色又从我眼前滑过，但是再也没有回到瓶子里。我捡起地上的那只金鱼，无能为力，只是眼睁睁看着它挣扎，再挣扎，拼命的挣扎，然后喘不过最后一口气，安静的躺在我的手心里。死了！我并没有感到任何的悲伤，反而对手里这个小小的生命感到一些敬佩。很镇定的，我把它埋在院子里，我想这样会好点。瓶子里剩下一只金鱼，我以为它会孤单的死去，
<br>没想到，那只金鱼若无其事的活着。每天仍旧快乐的吃着饲料，在小小的空间里游来游去。
<br>
<br>我佩服金鱼。只是一个小小的玻璃瓶就可以生存，简单朴素。人如果能像金鱼那样容易满足该有多好，可是挺难，毕竟大多数的人有上进心，不甘心一辈子就这么平凡下去。我佩服金鱼，努力抓住每一次小小的机会（瓶子移动）改变自己生活中点点滴滴，虽然最后失败了，但是至少它有不断进步的勇气，至少它做出了最后的努力，不是吗？我佩服金鱼的坚强，即使一个人孤孤单单，仍然轻松的活着，开始新的生活，创造新的精彩。而不是活在过去，活在回忆里。
<br>
<br>直到现在，那只红色的金鱼仍然坚强的活着。我把它摆在书桌的一个角落。它时时刻刻提醒着我，我想有一天，我也能跟它们一样，简单，努力，坚强！！！', '生日的时候，妹送给我两只金鱼，一只黑的、一只红的。金鱼很小，自然占不了多大的地方，只需要一个不大的玻璃瓶。每天，往瓶子里扔几粒饲料，举手之劳，不足挂齿。但对于金鱼来说，这是一天最快乐的时候。十天后的一个下午，突然有了观赏金鱼的雅致。于是把装鱼的瓶子移动至房间一个光线充足的角落。新的环境，新的气象，金鱼似乎也感觉到了――两只鱼快乐的游着。呼吸着新的空气，享受着新的改变。或许是因为金鱼太高兴了，只看见一道黑色从我眼前滑过，瞬间又落回瓶子里。很漂亮，虽然不及彩虹。还没等我反应过来，另一道黑色又从我眼前滑过，但是再也没有回到瓶子里。我捡起地上的那只金鱼，无能为力，只是眼睁睁看着它挣扎，再挣扎，拼命的挣扎，然后喘不过最后一口气，安静的躺在我的手心里。死了！我并没有感到任何的悲伤，反而对手里这个小小的生命感到一些敬佩。很镇定的，我把它埋在院子里，我想这样会好点。瓶子里剩下一只金鱼，我以为它会孤单的死去，

没想到，那只金鱼若无其事的活着。每天仍旧快乐的吃着饲料，在小小的空间里游来游去。

我佩服金鱼。只是一个小小的玻璃瓶就可以生存，简单朴素。人如果能像金鱼那样容易满足该有多好，可是挺难，毕竟大多数的人有上进心，不甘心一辈子就这么平凡下去。我佩服金鱼，努力抓住每一次小小的机会（瓶子移动）改变自己生活中点点滴滴，虽然最后失败了，但是至少它有不断进步的勇气，至少它做出了最后的努力，不是吗？我佩服金鱼的坚强，即使一个人孤孤单单，仍然轻松的活着，开始新的生活，创造新的精彩。而不是活在过去，活在回忆里。

直到现在，那只红色的金鱼仍然坚强的活着。我把它摆在书桌的一个角落。它时时刻刻提醒着我，我想有一天，我也能跟它们一样，简单，努力，坚强！！！', '~你爱再浓烈也是条抛物线

